// ─── SMART TTS (via /api/tts Netlify function → ElevenLabs) ─────────────────

let _ttsAudio = null;
function speakElevenLabs(text, voiceId, { onStart, onEnd } = {}, uid = "") {
  // Stop any playing audio
  if (_ttsAudio) { try { _ttsAudio.pause(); } catch {} _ttsAudio = null; }

  if (onStart) onStart();
  fetch("/api/tts", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, uid }),
  })
    .then(r => r.ok ? r.blob() : null)
    .then(blob => {
      if (!blob) { if (onEnd) onEnd(); return; }
      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);
      _ttsAudio = audio;
      audio.onended = () => { URL.revokeObjectURL(url); _ttsAudio = null; if (onEnd) onEnd(); };
      audio.onerror = () => { URL.revokeObjectURL(url); _ttsAudio = null; if (onEnd) onEnd(); };
      audio.play().catch(() => { if (onEnd) onEnd(); });
    })
    .catch(() => { if (onEnd) onEnd(); });
}

